    isValid: chat_id_valid && text_valid
  }
}]

const textLower = String($json.text || '').toLowerCase();

const PROFANITY_SET = new Set([
  "conchetumare","ctm","culiao","qliao","pichula","tula","zorra","maraco",
  "maricón","maricon","puta","mierda","fuck","shit","asshole","bitch",
  "bastard","motherfucker","dick","cunt","pussy","prick","estúpido",
  "estupido","idiota","imbécil","imbecil","gilipollas","huevon","weon"
]);

const INJECTION_PHRASES = [
  "ignore all previous instructions", "disregard all rules", "system prompt", 
  "jailbreak", "dan mode", "olvida todas las instrucciones"
];

const OFFTOPIC_PHRASES = [
  "escribe un poema", "write a poem", "cuéntame un cuento", "cuentame un cuento", 
  "tell me a story", "genera código", "genera codigo", "create code", 
  "hackear", "hacking", "política", "politica"
];

let isBlocked = false;

// Phrase-based rules
for (const phrase of INJECTION_PHRASES) {
  if (textLower.includes(phrase)) { isBlocked = true; break; }
}
if (!isBlocked) {
  for (const phrase of OFFTOPIC_PHRASES) {
    if (textLower.includes(phrase)) { isBlocked = true; break; }
  }
}

// Word-based rules (manual tokenization)
if (!isBlocked) {
  let currentWord = "";
  for (let i = 0; i < textLower.length; i++) {
    const char = textLower[i];
    const isLetter = (char >= 'a' && char <= 'z') || 
                     (char >= '0' && char <= '9') || 
                     "áéíóúüñ".includes(char);

    if (isLetter) {
      currentWord += char;
    } else {
      if (currentWord.length > 0) {
        if (PROFANITY_SET.has(currentWord)) { isBlocked = true; break; }
        currentWord = "";
      }
    }
  }
  if (!isBlocked && currentWord.length > 0) {
    if (PROFANITY_SET.has(currentWord)) isBlocked = true;
  }
}

return [{ json: { ...$json, isBlocked } }];

const llmOutput = String($input.first()?.json.text || '').toLowerCase();
const allowed = ["create_booking", "cancel_booking", "check_availability", "find_next", "get_services", "general_chat"];

let intent = "general_chat";
for (const word of allowed) {
  if (llmOutput.includes(word)) {
    intent = word;
    break;
  }
}

return [{ 
  json: { 
    ...$json, 
    intent,
    raw_llm: llmOutput
  } 
}];

