return [{ json: { success: false, error_message: "No branch executed" } }];

// UNIFIED FORMATTER - Single node replaces all 9 duplicate formatters
const input = $input.first()?.json || {};
const isBlocked = input.isBlocked === true || input.isBlocked === "true";
const isValid = input.isValid !== false && input.isValid !== "false";

let success = true;
let error_code = null;
let error_message = null;

if (isBlocked) {
  success = false;
  error_code = "SECURITY_BLOCKED";
  error_message = "Acceso denegado por reglas de seguridad";
} else if (!isValid) {
  success = false;
  error_code = "VALIDATION_ERROR";
  error_message = "Datos de entrada inválidos o insuficientes";
} else if (input.success === false) {
  success = false;
  error_code = input.error_code || "EXECUTION_ERROR";
  error_message = input.error_message || "Error interno";
}

let aiResp = input.text || input.ai_response || input.message?.content || input.output || "";
if (!success && !aiResp) aiResp = error_message;
if (!aiResp) aiResp = "Procesado correctamente.";

if (typeof aiResp === "string") {
  aiResp = aiResp.replace(/^["']|["']$/g, "").trim();
}

// ✅ FIXED: Use isExecuted guard to prevent VM crash (GEMINI.md §5)
let chatId = input.chat_id || 0;
if (!chatId) {
  if ($('Rule Firewall').isExecuted) {
    chatId = $('Rule Firewall').first().json.chat_id;
  }
}

return [{
  json: {
    success,
    error_code,
    error_message,
    data: {
      intent: input.intent || $('Intent Normalizer').first().json.intent || "GENERAL",
      chat_id: chatId,
      ai_response: aiResp
    },
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      workflow_id: "NN_03",
      version: '2.0.0'
    }
  }
}];

